const { DynamoDBClient } = require('@aws-sdk/client-dynamodb');
const { DynamoDBDocumentClient, UpdateCommand } = require('@aws-sdk/lib-dynamodb');
const { SQSClient, DeleteMessageCommand, ChangeMessageVisibilityCommand } = require('@aws-sdk/client-sqs');
const https = require('https');

const dynamoClient = new DynamoDBClient({});
const docClient = DynamoDBDocumentClient.from(dynamoClient);
const sqsClient = new SQSClient({});

const ORDERS_TABLE = process.env.ORDERS_TABLE;
const PAYMENT_API_URL = process.env.PAYMENT_API_URL;
const PAYMENT_API_KEY = process.env.PAYMENT_API_KEY;
const MAX_RETRIES = 3;
const VISIBILITY_TIMEOUT = 300;

exports.handler = async (event) => {
  const results = {
    successful: 0,
    failed: 0,
    errors: []
  };

  for (const record of event.Records) {
    try {
      await processOrder(record);
      results.successful++;
    } catch (error) {
      results.failed++;
      results.errors.push({
        messageId: record.messageId,
        error: error.message
      });
      
      console.error('Error processing order:', {
        messageId: record.messageId,
        errorMessage: error.message,
        errorStack: error.stack
      });

      await handleFailedMessage(record, error);
    }
  }

  console.log('Batch processing complete:', results);
  
  return {
    statusCode: 200,
    body: JSON.stringify(results)
  };
};

async function processOrder(record) {
  const order = JSON.parse(record.body);
  
  if (!order.orderId || !order.amount || !order.customerId) {
    throw new Error('Invalid order data: missing required fields');
  }

  const receiptHandle = record.receiptHandle;
  const queueUrl = getQueueUrl(record.eventSourceARN);

  await extendVisibilityTimeout(queueUrl, receiptHandle);

  await updateOrderStatus(order.orderId, 'PROCESSING');

  const paymentResult = await processPayment(order);

  await updateOrderStatus(order.orderId, 'COMPLETED', paymentResult);

  await deleteMessage(queueUrl, receiptHandle);
}

async function processPayment(order) {
  return new Promise((resolve, reject) => {
    const paymentData = JSON.stringify({
      orderId: order.orderId,
      amount: order.amount,
      customerId: order.customerId,
      currency: order.currency || 'USD'
    });

    const url = new URL(PAYMENT_API_URL);
    const options = {
      hostname: url.hostname,
      port: url.port || 443,
      path: url.pathname,
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'Content-Length': Buffer.byteLength(paymentData),
        'Authorization': `Bearer ${PAYMENT_API_KEY}`,
        'X-Request-ID': order.orderId
      },
      timeout: 30000
    };

    const req = https.request(options, (res) => {
      let data = '';

      res.on('data', (chunk) => {
        data += chunk;
      });

      res.on('end', () => {
        if (res.statusCode >= 200 && res.statusCode < 300) {
          try {
            const result = JSON.parse(data);
            resolve(result);
          } catch (e) {
            reject(new Error('Invalid payment API response'));
          }
        } else {
          reject(new Error(`Payment API error: ${res.statusCode} - ${data}`));
        }
      });
    });

    req.on('error', (error) => {
      reject(new Error(`Payment API request failed: ${error.message}`));
    });

    req.on('timeout', () => {
      req.destroy();
      reject(new Error('Payment API request timeout'));
    });

    req.write(paymentData);
    req.end();
  });
}

async function updateOrderStatus(orderId, status, paymentResult = null) {
  const params = {
    TableName: ORDERS_TABLE,
    Key: { orderId },
    UpdateExpression: 'SET #status = :status, updatedAt = :updatedAt',
    ExpressionAttributeNames: {
      '#status': 'status'
    },
    ExpressionAttributeValues: {
      ':status': status,
      ':updatedAt': new Date().toISOString()
    }
  };

  if (paymentResult) {
    params.UpdateExpression += ', paymentId = :paymentId, paymentStatus = :paymentStatus';
    params.ExpressionAttributeValues[':paymentId'] = paymentResult.paymentId;
    params.ExpressionAttributeValues[':paymentStatus'] = paymentResult.status;
  }

  await docClient.send(new UpdateCommand(params));
}

async function extendVisibilityTimeout(queueUrl, receiptHandle) {
  try {
    await sqsClient.send(new ChangeMessageVisibilityCommand({
      QueueUrl: queueUrl,
      ReceiptHandle: receiptHandle,
      VisibilityTimeout: VISIBILITY_TIMEOUT
    }));
  } catch (error) {
    console.warn('Failed to extend visibility timeout:', error.message);
  }
}

async function deleteMessage(queueUrl, receiptHandle) {
  try {
    await sqsClient.send(new DeleteMessageCommand({
      QueueUrl: queueUrl,
      ReceiptHandle: receiptHandle
    }));
  } catch (error) {
    console.error('Failed to delete message from queue:', error.message);
  }
}

async function handleFailedMessage(record, error) {
  const queueUrl = getQueueUrl(record.eventSourceARN);
  const receiptHandle = record.receiptHandle;
  const approximateReceiveCount = parseInt(record.attributes.ApproximateReceiveCount || '0');

  if (approximateReceiveCount >= MAX_RETRIES) {
    console.error('Message exceeded max retries, will be moved to DLQ:', {
      messageId: record.messageId,
      receiveCount: approximateReceiveCount
    });
    
    try {
      const order = JSON.parse(record.body);
      await updateOrderStatus(order.orderId, 'FAILED', { error: error.message });
    } catch (e) {
      console.error('Failed to update order status for failed message:', e.message);
    }
  }
}

function getQueueUrl(eventSourceARN) {
  const arnParts = eventSourceARN.split(':');
  const region = arnParts[3];
  const accountId = arnParts[4];
  const queueName = arnParts[5];
  return `https://sqs.${region}.amazonaws.com/${accountId}/${queueName}`;
}